onClipEvent (enterFrame) {
	_parent.攻击时可斜向改变移动方向(25);
}

onClipEvent(enterFrame){
   _parent.攻击时移动(_parent._parent.跑X速度 * 2,_parent._parent.跑X速度 * 2);
}

onClipEvent (enterFrame) {
	if (_parent._parent._name == _root.控制目标)
	{//Key.isDown(_parent._parent.A键)更换为_parent._parent.动作A
		/*
		if (_parent._parent.被动技能.上挑 && _parent._parent.被动技能.上挑.启用 && _parent._parent.动作A && _parent._parent.动作B)
		{
		_parent._parent.状态改变("兵器跳");
		}
		*/
		if (_parent._parent.被动技能.拳脚空中连招 && _parent._parent.被动技能.拳脚空中连招.启用 )
		{
			if(Key.isDown(_parent._parent.A键)){
				if(_parent.不按攻击){
					_parent.gotoAndPlay("旋风腿");
				}
			}else{
				_parent.不按攻击 = true;
			}
		}


		if (!_parent._parent.飞行浮空 && _parent._parent.动作B)
		{
			_parent._parent.状态改变("空手跳");
		}


	}
}

onClipEvent(load){
	子弹属性 = _root.子弹属性初始化(this);

	//以下部分只需要更改需要更改的属性,其余部分可注释掉
	子弹属性.声音 = "";
	子弹属性.霰弹值 = 1;
	子弹属性.子弹散射度 = 0;
	子弹属性.子弹种类 = "近战子弹";

	自机 = _root.获得父节点(this,2);
	子弹属性.子弹威力 = 自机.空手攻击力 * 2;
	if(_parent._parent.被动技能.拳脚空中连招 && _parent._parent.被动技能.拳脚空中连招.等级){
		子弹属性.子弹威力 +=  _parent._parent.空手攻击力 *  _parent._parent.被动技能.拳脚空中连招.等级 / 10;
	}

	子弹属性.子弹速度 = 0;
	子弹属性.Z轴攻击范围 = 35;
	子弹属性.击倒率 = 1;
	子弹属性.垂直击退速度 = 2;

	子弹属性.区域定位area = this.area;
	_root.子弹区域shoot传递(子弹属性);
}
