onClipEvent (enterFrame) {
	if (_parent._parent._name == _root.控制目标)
	{
		if (_parent._parent.被动技能.拳脚空中连招 && _parent._parent.被动技能.拳脚空中连招.启用 )
		{
			if (!Key.isDown(_parent._parent.A键))
			{
				_parent.不按攻击 = true;
			}
		}

	}
}
